patch:
--- a/adder.v
+++ b/adder.v
@@ -1,5 +1,5 @@
 module 4bit_adder (
   input [3:0] a,
   input [3:0] b,
   output [4:0] sum
 );
@@ -12,7 +12,7 @@
 module top_adder (
   input [3:0] x, y,
   output [4:0] result
 );

-  4bit_adder add_inst (.ain(x), .bin(y), .sumout(result));
+  4bit_adder add_inst (.a(x), .b(y), .sum(result));

 endmodule

before_code:
module 4bit_adder (
  input [3:0] a,
  input [3:0] b,
  output [4:0] sum
);
  assign sum = a + b;
endmodule

module top_adder (
  input [3:0] x, y,
  output [4:0] result
);

  4bit_adder add_inst (.ain(x), .bin(y), .sumout(result));

endmodule

after_code:
module 4bit_adder (
  input [3:0] a,
  input [3:0] b,
  output [4:0] sum
);
  assign sum = a + b;
endmodule

module top_adder (
  input [3:0] x, y,
  output [4:0] result
);

  4bit_adder add_inst (.a(x), .b(y), .sum(result));

endmodule
